1	'use client';
2	
3	import { Box, Button, Group, NativeSelect, Paper, Stack } from '@mantine/core';
4	import { useForm } from '@mantine/form';
5	import { useDisclosure } from '@mantine/hooks';
6	import { notifications } from '@mantine/notifications';
7	import { IconAlertTriangle, IconCheck } from '@tabler/icons-react';
8	import { useRouter } from 'next/navigation';
9	
10	import { config } from '@/lib/config';
11	import type { SetGameResultProxy, SetGameWinner } from '@/types/actions/SetGameResult';
12	
13	export interface GameResultFormProps {
14	    gameDayId: number;
15	    bibs: 'A' | 'B' | null;
16	    winners: SetGameWinner;
17	    setGameResult: SetGameResultProxy;
18	}
19	
20	export const GameResultForm = ({
21	    gameDayId,
22	    bibs,
23	    winners,
24	    setGameResult,
25	}: GameResultFormProps) => {
26	    const router = useRouter();
27	    const [isSaving, { open: setSaving, close: setSaved }] = useDisclosure(false);
28	    const form = useForm<{
29	        bibs: 'A' | 'B' | 'none';
30	        winner: 'A' | 'B' | 'draw' | 'none';
31	    }>({
32	        initialValues: {
33	            bibs: bibs ?? 'none',
34	            winner: winners ?? 'none',
35	        },
36	    });
37	
38	    const handleSave = async (values: { bibs: 'A' | 'B' | 'none'; winner: 'A' | 'B' | 'draw' | 'none' }) => {
39	        const notificationId = 'game-result-update';
40	        notifications.show({
41	            id: notificationId,
42	            loading: true,
43	            title: 'Updating game details',
44	            message: 'Saving bibs and result...',
45	            autoClose: false,
46	            withCloseButton: false,
47	        });
48	
49	        setSaving();
50	        try {
51	            await setGameResult({
52	                gameDayId,
53	                bibs: values.bibs === 'none' ? null : values.bibs,
54	                winner: values.winner === 'none' ? null : values.winner,
55	            });
56	
57	            notifications.update({
58	                id: notificationId,
59	                color: 'teal',
60	                title: 'Game updated',
61	                message: 'Bibs and result were updated.',
62	                icon: <IconCheck size={config.notificationIconSize} />,
63	                loading: false,
64	                autoClose: config.notificationAutoClose,
65	            });
66	
67	            form.resetDirty(values);
68	            router.refresh();
69	        } catch (err) {
70	            const errorMessage = err instanceof Error ? err.message : 'Failed to update game';
71	            notifications.update({
72	                id: notificationId,
73	                color: 'red',
74	                title: 'Error',
75	                message: errorMessage,
76	                icon: <IconAlertTriangle size={config.notificationIconSize} />,
77	                loading: false,
78	                autoClose: false,
79	                withCloseButton: true,
80	            });
81	        } finally {
82	            setSaved();
83	        }
84	    };
85	
86	    return (
87	        <Box component="form" onSubmit={form.onSubmit(handleSave)}>
88	            <Paper withBorder p="md" shadow="xs" radius="md">
89	                <Stack gap="sm">
90	                    <Group grow>
91	                        <NativeSelect
92	                            label="Bibs"
93	                            data={[
94	                                { value: 'none', label: 'Not set' },
95	                                { value: 'A', label: 'Team A wore bibs' },
96	                                { value: 'B', label: 'Team B wore bibs' },
97	                            ]}
98	                            {...form.getInputProps('bibs')}
99	                        />
100	                        <NativeSelect
101	                            label="Result"
102	                            data={[
103	                                { value: 'none', label: 'Not set' },
104	                                { value: 'A', label: 'Team A won' },
105	                                { value: 'draw', label: 'Draw' },
106	                                { value: 'B', label: 'Team B won' },
107	                            ]}
108	                            {...form.getInputProps('winner')}
109	                        />
110	                    </Group>
111	                    <Group justify="flex-end">
112	                        <Button
113	                            type="submit"
114	                            loading={isSaving}
115	                            disabled={!form.isDirty()}
116	                        >
117	                            Save
118	                        </Button>
119	                    </Group>
120	                </Stack>
121	            </Paper>
122	        </Box>
123	    );
124	};
