1	'use client';
2	
3	import {
4	    Anchor,
5	    Avatar,
6	    Badge,
7	    Box,
8	    Button,
9	    Checkbox,
10	    Flex,
11	    NativeSelect,
12	    Stack,
13	    Text,
14	    TextInput,
15	    Title,
16	} from '@mantine/core';
17	import { useForm } from '@mantine/form';
18	import { notifications } from '@mantine/notifications';
19	import { IconAlertTriangle, IconCheck } from '@tabler/icons-react';
20	import { zod4Resolver } from 'mantine-form-zod-resolver';
21	import { PlayerResponse } from 'prisma/generated/enums';
22	import { useState } from 'react';
23	import z from 'zod';
24	
25	import { config } from '@/lib/config';
26	import { captureUnexpectedError } from '@/lib/observability/sentry';
27	import {
28	    InvitationResponseInputSchema,
29	    SubmitGameInvitationResponseProxy,
30	} from '@/types/actions/SubmitGameInvitationResponse';
31	import { GameInvitationResponseDetails } from '@/types/GameInvitationResponseDetails';
32	
33	const formSchema = InvitationResponseInputSchema.omit({ token: true }).extend({
34	    comment: z.string().max(127).optional(),
35	});
36	type FormValues = z.infer<typeof formSchema>;
37	
38	const responseOptions = [
39	    { value: PlayerResponse.Yes, label: 'Yes' },
40	    { value: PlayerResponse.No, label: 'No' },
41	    { value: PlayerResponse.Dunno, label: 'Dunno' },
42	];
43	
44	/**
45	 * Responses that players can select themselves in this form.
46	 */
47	const playerEditableResponses = new Set<PlayerResponse>([
48	    PlayerResponse.Yes,
49	    PlayerResponse.No,
50	    PlayerResponse.Dunno,
51	]);
52	
53	/**
54	 * Returns the initial response value used by the editable select input.
55	 *
56	 * Player invitations can carry admin-only response values (for example
57	 * `Excused`) that should still be displayed in the summary, but players can
58	 * only submit Yes/No/Dunno from this form.
59	 *
60	 * @param response - Incoming invitation response from query details.
61	 * @returns The player-editable response value for the form select.
62	 */
63	function getInitialPlayerResponse(responseInput: GameInvitationResponseDetails['response']) {
64	    const response = responseInput &&
65	        playerEditableResponses.has(responseInput) ? responseInput : PlayerResponse.Yes;
66	
67	    return response;
68	}
69	
70	interface Props {
71	    details: GameInvitationResponseDetails;
72	    onSubmitGameInvitationResponse: SubmitGameInvitationResponseProxy;
73	}
74	
75	export const GameInvitationResponseForm = ({
76	    details,
77	    onSubmitGameInvitationResponse,
78	}: Props) => {
79	    const response = getInitialPlayerResponse(details.response);
80	    const [currentResponse, setCurrentResponse] = useState(details.response);
81	    const [currentComment, setCurrentComment] = useState(details.comment);
82	    const [canSubmitWithoutChanges, setCanSubmitWithoutChanges] = useState(!details.response);
83	
84	    const form = useForm<FormValues>({
85	        initialValues: {
86	            response,
87	            goalie: details.goalie ?? false,
88	            comment: details.comment ?? '',
89	        },
90	        validate: zod4Resolver(formSchema),
91	        validateInputOnBlur: true,
92	    });
93	
94	    /**
95	     * The form is dirty if the user has changed a field, or if there is no
96	     * saved response yet. In that case, submission is allowed without
97	     * interaction so users can quickly confirm the default Yes value. Once a
98	     * response has been saved, the button should disable again until the form
99	     * changes.
100	     */
101	    const isFormDirty = form.isDirty() || canSubmitWithoutChanges;
102	
103	    const handleSubmit = async (values: FormValues) => {
104	        const id = notifications.show({
105	            loading: true,
106	            title: 'Saving response',
107	            message: 'Saving your response...',
108	            autoClose: false,
109	            withCloseButton: false,
110	        });
111	
112	        try {
113	            await onSubmitGameInvitationResponse({
114	                token: details.token,
115	                response: values.response,
116	                goalie: values.goalie,
117	                comment: values.comment?.trim() ?? null,
118	            });
119	
120	            setCurrentResponse(values.response);
121	            setCurrentComment(values.comment?.trim() ?? '');
122	            setCanSubmitWithoutChanges(false);
123	
124	            notifications.update({
125	                id,
126	                color: 'teal',
127	                title: 'Response saved',
128	                message: 'Your response has been updated.',
129	                icon: <IconCheck size={config.notificationIconSize} />,
130	                loading: false,
131	                autoClose: config.notificationAutoClose,
132	            });
133	        } catch (error) {
134	            captureUnexpectedError(error, {
135	                layer: 'client',
136	                component: 'GameInvitationResponseForm',
137	                action: 'submitResponse',
138	                route: '/footy/game/[id]',
139	                extra: {
140	                    playerId: details.playerId,
141	                    gameDayId: details.gameDayId,
142	                    response: values.response,
143	                },
144	            });
145	            const message = error instanceof Error ? error.message : 'Failed to save response';
146	            notifications.update({
147	                id,
148	                color: 'red',
149	                title: 'Error',
150	                message,
151	                icon: <IconAlertTriangle size={config.notificationIconSize} />,
152	                loading: false,
153	                autoClose: false,
154	                withCloseButton: true,
155	            });
156	        }
157	    };
158	
159	    const responseColor = {
160	        [PlayerResponse.Yes.toString()]: 'green',
161	        [PlayerResponse.No.toString()]: 'red',
162	        [PlayerResponse.Dunno.toString()]: 'grey',
163	    } as const;
164	    const displayResponse = currentResponse ? (
165	        <Badge color={responseColor[currentResponse.toString()]} variant="filled" size="sm">
166	            {currentResponse}
167	        </Badge>
168	    ) : (
169	        <Badge color="grey" variant="filled" size="sm">
170	            No response yet
171	        </Badge>
172	    );
173	    const displayComment = currentComment ? `("${currentComment}")` : '';
174	    const playerLink = details.playerLogin ? `/footy/player/${details.playerLogin}` : `/footy/player/${details.playerId}`;
175	
176	    return (
177	        <Box component="form" onSubmit={form.onSubmit(handleSubmit)}>
178	            <Stack gap="md">
179	                <Title order={2}>
180	                    {currentResponse ? 'Thanks for Your Response' : 'Enter Your Response'}
181	                </Title>
182	                <Flex align="center" gap="md" wrap="wrap">
183	                    <Avatar
184	                        src={`/api/footy/player/${details.playerId}/mugshot`}
185	                        alt={details.playerName}
186	                        size={48}
187	                        radius="xl"
188	                    />
189	                    <Anchor href={playerLink}>{details.playerName}</Anchor>: {displayResponse} {displayComment}
190	                </Flex>
191	                <Text>
192	                    You can change it later if you need to, even if the teams have been picked - either by clicking
193	                    on the link in the email you received, or by logging in to the site at{' '}
194	                    <Anchor href={`/footy/game/${details.gameDayId}`}>the game page</Anchor>. If you can&apos;t get to
195	                    a computer, call my mobile on <strong>{config.organiserPhoneNumber}</strong>.
196	                </Text>
197	                <Text>Cheers,</Text>
198	                <Text>Jon</Text>
199	                <NativeSelect
200	                    label="Response"
201	                    data={responseOptions}
202	                    {...form.getInputProps('response')}
203	                />
204	                <Checkbox
205	                    label="Goalie"
206	                    {...form.getInputProps('goalie', { type: 'checkbox' })}
207	                />
208	                <TextInput
209	                    label="Optional comment/excuse"
210	                    maxLength={127}
211	                    {...form.getInputProps('comment')}
212	                />
213	                <Button type="submit" w="fit-content" disabled={!isFormDirty}>
214	                    Save Response
215	                </Button>
216	            </Stack>
217	        </Box>
218	    );
219	};
